define(['core/notification'],function(Notification){var PLYR_URL=M.cfg.wwwroot+'/mod/videoplayer/thirdpartylibs/plyr/plyr.min.js';var plyrPromise=null;var blockBrowserMediaActions=function(event){event.preventDefault();event.stopPropagation();return false;};var loadAmdPlyr=function(resolve,reject){if(window.require){window.require(['Plyr'],function(Plyr){resolve(Plyr);},function(){reject(new Error('Plyr AMD module could not be resolved'));});return;}reject(new Error('Plyr did not expose window.Plyr'));};var loadPlyr=function(){if(window.Plyr){return Promise.resolve(window.Plyr);}if(!plyrPromise){plyrPromise=new Promise(function(resolve,reject){var existing=document.querySelector('script[data-mod-videoplayer-plyr="1"]');var script=existing||document.createElement('script');script.onload=function(){if(window.Plyr){resolve(window.Plyr);return;}loadAmdPlyr(resolve,reject);};script.onerror=function(){reject(new Error('Local Plyr library could not be loaded'));};if(existing){loadAmdPlyr(resolve,reject);return;}script.src=PLYR_URL;script.async=true;script.setAttribute('data-mod-videoplayer-plyr','1');document.head.appendChild(script);});}return plyrPromise;};var hardenVideo=function(node){node.setAttribute('controlsList','nodownload noplaybackrate');node.setAttribute('draggable','false');node.disablePictureInPicture=true;node.addEventListener('contextmenu',blockBrowserMediaActions,true);node.addEventListener('dragstart',blockBrowserMediaActions,true);node.addEventListener('selectstart',blockBrowserMediaActions,true);};var init=function(){var nodes=Array.prototype.slice.call(document.querySelectorAll('.js-drive-resource-video'));if(!nodes.length){return;}nodes.forEach(hardenVideo);loadPlyr().then(function(Plyr){nodes.forEach(function(node){if(node.dataset.plyrReady==='1'){return;}node.dataset.plyrReady='1';new Plyr(node,{controls:['play-large','play','rewind','fast-forward','progress','current-time','duration','mute','volume','settings','fullscreen'],settings:['speed'],seekTime:10,speed:{selected:1,options:[0.5,0.75,1,1.25,1.5,2]},hideControls:true,keyboard:{focused:true,global:false},tooltips:{controls:true,seek:true},storage:{enabled:false},fullscreen:{enabled:true,fallback:true,iosNative:true}});});}).catch(function(error){if(window.console){window.console.warn(error.message||error);}Notification.addNotification({message:M.util.get_string('plyrmissing','mod_videoplayer'),type:'warning'});});};return{init:init};});
